def conn():
    c = sqlite3.connect(DB_PATH)
    c.row_factory = sqlite3.Row
    return c
def sb_students_list():
    if not supabase:
        return None
    res = supabase.table('students').select('*').order('id', desc=True).execute()
    return res.data or []

def sb_student_by_code(code):
    if not supabase:
        return None
    res = supabase.table('students').select('*').eq('code', code).limit(1).execute()
    data = res.data or []
    return data[0] if data else None

def sb_add_student(name, code):
    if not supabase:
        return None
    return supabase.table('students').insert({
        'name': name,
        'code': code
    }).execute()
def sb_delete_exam(exam_id):
    if not supabase:
        return None
    supabase.table('exam_questions').delete().eq('exam_id', exam_id).execute()
    return supabase.table('exams').delete().eq('id', exam_id).execute()

def sb_questions_by_chapter(chapter_no):
    if not supabase:
        return []
    res = supabase.table('questions') \
        .select('*') \
        .eq('chapter', chapter_no) \
        .order('question_no') \
        .order('id') \
        .execute()
    return res.data or []


def sb_delete_student(sid):
    if not supabase:
        return None
    supabase.table('answers').delete().eq('student_id', sid).execute()
    supabase.table('students').delete().eq('id', sid).execute()
