EXTRA_QUESTIONS.extend(MORE_REAL_QUESTIONS)

def cleanup_duplicate_questions(c):
    cur = c.cursor()
    dup_rows = cur.execute("""
        SELECT MIN(id) AS keep_id, chapter, text
        FROM questions
        WHERE text IS NOT NULL AND TRIM(text) <> ''
        GROUP BY chapter, text
        HAVING COUNT(*) > 1
    """).fetchall()
    for row in dup_rows:
        keep_id = row['keep_id']
        chapter = row['chapter']
        textv = row['text']
        cur.execute('DELETE FROM questions WHERE chapter=? AND text=? AND id<>?', (chapter, textv, keep_id))
    c.commit()

def init_db():
    c = conn()
    cur = c.cursor()
    cur.executescript('''
    CREATE TABLE IF NOT EXISTS teacher_profile (
        id INTEGER PRIMARY KEY CHECK(id=1),
        name TEXT, phone TEXT, location TEXT, instagram TEXT
    );
    CREATE TABLE IF NOT EXISTS teacher_users (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        username TEXT UNIQUE,
        password TEXT
    );
    CREATE TABLE IF NOT EXISTS students (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        code TEXT UNIQUE,
        name TEXT
    );
    CREATE TABLE IF NOT EXISTS questions (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        chapter INTEGER,
        display_type TEXT,
        text TEXT,
        answer TEXT,
        is_wazari INTEGER DEFAULT 0,
        qtype TEXT,
        keywords TEXT,
        image_path TEXT,
        file_path TEXT
    );
    CREATE TABLE IF NOT EXISTS answers (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        student_id INTEGER,
        question_id INTEGER,
        text_answer TEXT,
        image_path TEXT,
        file_path TEXT,
        smart_result TEXT,
        teacher_note TEXT,
        teacher_score TEXT,
        created_at TEXT
    );
    CREATE TABLE IF NOT EXISTS exams (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        title TEXT,
        exam_date TEXT,
        exam_time TEXT,
        ampm TEXT,
        note TEXT
    );
    CREATE TABLE IF NOT EXISTS exam_questions (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        exam_id INTEGER,
        question_id INTEGER,
        custom_text TEXT,
        custom_answer TEXT,
        custom_type TEXT,
        custom_keywords TEXT,
        custom_image_path TEXT,
        custom_file_path TEXT,
        is_wazari INTEGER DEFAULT 0
    );
    ''')
    c.commit()
    ensure_column(cur, 'questions', 'question_no', 'INTEGER')
    ensure_column(cur, 'questions', 'answer_image_path', 'TEXT')

    cur.execute('SELECT COUNT(*) AS n FROM teacher_users')
    if cur.fetchone()['n'] == 0:
        cur.execute('INSERT INTO teacher_users(username,password) VALUES (?,?)', (TEACHER_DEFAULT['username'], TEACHER_DEFAULT['password']))

    cur.execute('SELECT COUNT(*) AS n FROM teacher_profile')
    if cur.fetchone()['n'] == 0:
        cur.execute('INSERT INTO teacher_profile(id,name,phone,location,instagram) VALUES (1,?,?,?,?)',
                    (TEACHER_DEFAULT['name'], TEACHER_DEFAULT['phone'], TEACHER_DEFAULT['location'], TEACHER_DEFAULT['instagram']))

    cur.execute('SELECT COUNT(*) AS n FROM students')
    if cur.fetchone()['n'] == 0:
        cur.execute('INSERT INTO students(code,name) VALUES (?,?)', ('ST1001', 'طالب تجريبي 1'))
        cur.execute('INSERT INTO students(code,name) VALUES (?,?)', ('ST1002', 'طالب تجريبي 2'))

    cur.execute('SELECT COUNT(*) AS n FROM questions')
    if cur.fetchone()['n'] == 0:
        cur.executemany('''INSERT INTO questions(chapter,display_type,text,answer,image_path,is_wazari,qtype,keywords)
                        VALUES (?,?,?,?,?,?,?,?)''', SEED_QUESTIONS)
    existing_texts = {row['text'] for row in cur.execute('SELECT text FROM questions').fetchall()}
    extras_to_add = [q for q in EXTRA_QUESTIONS if q[2] not in existing_texts]
    if extras_to_add:
        cur.executemany('''INSERT INTO questions(chapter,display_type,text,answer,image_path,is_wazari,qtype,keywords)
                        VALUES (?,?,?,?,?,?,?,?)''', extras_to_add)
    for ch in CHAPTERS.keys():
        rows = cur.execute('SELECT id FROM questions WHERE chapter=? ORDER BY COALESCE(question_no, 999999), id ASC', (ch,)).fetchall()
        for i, r in enumerate(rows, 1):
            cur.execute('UPDATE questions SET question_no=COALESCE(question_no, ?) WHERE id=?', (i, r['id']))
            try:
                c.execute("ALTER TABLE answers ADD COLUMN result TEXT")
            except:
                pass
    c.commit()
    cleanup_duplicate_questions(c)
    c.close()


def teacher_required(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        if session.get('role') != 'teacher':
            return redirect(url_for('teacher_login'))
        return f(*args, **kwargs)
    return wrapper


def student_required(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        if session.get('role') != 'student':
            return redirect(url_for('student_login'))
        return f(*args, **kwargs)
    return wrapper

def _compress_image_upload(file_storage):
    if Image is None:
        return None

    try:
        img = Image.open(file_storage.stream)
        img = ImageOps.exif_transpose(img)
        if img.mode not in ("RGB", "L"):
            img = img.convert("RGB")
        elif img.mode == "L":
            img = img.convert("RGB")

        max_size = (1400, 1400)
        img.thumbnail(max_size, Image.LANCZOS)

        name = f"{uuid4().hex}.webp"
        path = UPLOAD_DIR / name
        img.save(path, format="WEBP", quality=80, method=6)
        file_storage.stream.seek(0)
        return name
    except Exception:
        try:
            file_storage.stream.seek(0)
        except Exception:
            pass
        return None


def save_upload(field_name):
    f = request.files.get(field_name)
    if not f or not f.filename:
        return None

    ext = Path(secure_filename(f.filename)).suffix.lower()
    image_exts = {'.jpg', '.jpeg', '.png', '.webp', '.bmp', '.gif', '.tif', '.tiff'}

    if ext in image_exts:
        compressed_name = _compress_image_upload(f)
        if compressed_name:
            return compressed_name

    name = f"{uuid4().hex}{ext}"
    path = UPLOAD_DIR / name
    f.save(path)
    return name


def ensure_column(cur, table, column, definition):
    cols = [r[1] for r in cur.execute(f"PRAGMA table_info({table})").fetchall()]
    if column not in cols:
        cur.execute(f"ALTER TABLE {table} ADD COLUMN {column} {definition}")


def next_question_no(cur, chapter_no):
    row = cur.execute('SELECT COALESCE(MAX(question_no), 0) AS n FROM questions WHERE chapter=?', (chapter_no,)).fetchone()
    return int(row['n']) + 1


def renumber_chapter_questions(cur, chapter_no):
    rows = cur.execute('SELECT id FROM questions WHERE chapter=? ORDER BY COALESCE(question_no, 999999), id ASC', (chapter_no,)).fetchall()
    for i, r in enumerate(rows, 1):
        cur.execute('UPDATE questions SET question_no=? WHERE id=?', (i, r['id']))

def smart_grade(student_answer, model_answer, keywords, qtype):
    if not student_answer:
        return 'بانتظار المراجعة'
    sa = student_answer.strip().lower()
    ma = (model_answer or '').strip().lower()
    if qtype in ('mcq', 'blank', 'tf', 'truefalse'):
        if sa == ma:
            return 'صحيح'
        return 'خطأ'
    keys = [k.strip().lower() for k in (keywords or '').split('|') if k.strip()]
    if not keys:
        return 'تحتاج مراجعة الأستاذ'
    hits = sum(1 for k in keys if k in sa)
    ratio = hits / len(keys) if keys else 0
    if ratio >= 0.8:
        return 'صحيح غالبًا'
    if ratio >= 0.4:
        return 'ناقص'
    return 'خطأ غالبًا'


def display_exam_datetime(exam_row):
    d = exam_row['exam_date'] or ''
    t = exam_row['exam_time'] or ''
    a = exam_row['ampm'] or ''
    return f"{d} {t} {a}".strip()


def exam_status(exam_row):
    try:
        d = exam_row['exam_date']
        t = exam_row['exam_time']
        a = exam_row['ampm']
        if not (d and t and a):
            return 'غير محدد'
        hour, minute = [int(x) for x in t.split(':')]
        if a.upper() == 'PM' and hour != 12:
            hour += 12
        if a.upper() == 'AM' and hour == 12:
            hour = 0
        exam_dt = datetime.strptime(f"{d} {hour:02d}:{minute:02d}", '%Y-%m-%d %H:%M')
        now = datetime.now()
        if now.date() < exam_dt.date() or now < exam_dt:
            return 'قادم'
        return 'متاح الآن'
    except Exception:
        return 'غير محدد'


def render_base(title, body):
    return render_template_string('''
    <!doctype html>
    <html lang="ar" dir="rtl">
    <head>
      <meta charset="utf-8">
      <meta name="viewport" content="width=device-width, initial-scale=1">
      <title>{{ title }}</title>
      <style>
        body{font-family:Tahoma,Arial,sans-serif;background:#f5f7fb;margin:0;color:#1f2937}
        .wrap{max-width:1100px;margin:0 auto;padding:20px}
        .card{background:#fff;border-radius:16px;padding:18px;margin:12px 0;box-shadow:0 2px 10px rgba(0,0,0,.06)}
        .btn{display:inline-block;background:#2563eb;color:#fff;padding:10px 14px;border-radius:10px;text-decoration:none;border:0;cursor:pointer}
        .btn2{background:#059669}
        .btn3{background:#dc2626}
        input,select,textarea{width:100%;padding:10px;border:1px solid #d1d5db;border-radius:10px;box-sizing:border-box;margin-top:6px}
        textarea{min-height:90px}
        .grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px}
        .row{display:flex;gap:10px;flex-wrap:wrap}
        .tag{background:#fee2e2;color:#991b1b;border-radius:999px;padding:4px 10px;font-size:12px}
        .muted{color:#6b7280}.num{direction:ltr;unicode-bidi:embed}
        .q{border-top:1px solid #e5e7eb;padding-top:12px;margin-top:12px}
        .question-media{margin-top:10px}
        .question-media img{display:block;max-width:100%;height:auto;border-radius:12px}
        .answer-form{margin-top:15px}
        .answer-form textarea{min-height:120px}
        .answer-files{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:12px}
      </style>
    </head>
    <body>
      <div class="wrap">
        <div class="card"><h2>{{ title }}</h2>
          <div class="muted">برنامج فيزياء السادس العلمي</div>
          {% with messages = get_flashed_messages() %}{% if messages %}<div class="card">{% for m in messages %}<div>{{m}}</div>{% endfor %}</div>{% endif %}{% endwith %}
        </div>
        ''' + body + '''
      </div>
    </body>
    </html>
    ''', title=title, chapters=CHAPTERS)




