def sb_teacher_profile():
    if not supabase:
        return None
    res = supabase.table('teacher_profile').select('*').eq('id', 1).execute()
    data = res.data or []
    return data[0] if data else None

def sb_save_teacher_profile(name, phone, location, instagram):
    if not supabase:
        return None

    payload = {
        'name': name,
        'phone': phone,
        'location': location,
        'instagram': instagram
    }

    old = supabase.table('teacher_profile').select('id').eq('id', 1).execute()

    if old.data:
        return supabase.table('teacher_profile').update(payload).eq('id', 1).execute()
    else:
        payload['id'] = 1
        return supabase.table('teacher_profile').insert(payload).execute()


