def sb_question_by_id(qid):
    if not supabase:
        return None
    res = supabase.table('questions').select('*').eq('id', qid).limit(1).execute()
    data = res.data or []
    return data[0] if data else None
def sb_add_question(chapter_no, display_type, text_q, answer, answer_image, is_wazari, qtype, keywords, image, filex):
    if not supabase:
        return None

    c = conn()
    qno = next_question_no(c, chapter_no)
    c.close()

    return supabase.table('questions').insert({
        'chapter': chapter_no,
        'question_no': qno,
        'display_type': display_type,
        'text': text_q,
        'answer': answer,
        'answer_image_path': answer_image,
        'is_wazari': 1 if is_wazari else 0,
        'qtype': qtype,
        'keywords': keywords or '',
        'image_path': image,
        'file_path': filex
    }).execute()
def sb_add_answer(student_id, question_id, text_answer, image_path, file_path, smart_result):
    if not supabase:
        return None
    return supabase.table('answers').insert({
        'student_id': student_id,
        'question_id': question_id,
        'text_answer': text_answer,
        'image_path': image_path,
        'file_path': file_path,
        'smart_result': smart_result
    }).execute()

def sb_student_by_id(student_id):
    if not supabase:
        return None
    res = supabase.table('students').select('*').eq('id', student_id).limit(1).execute()
    data = res.data or []
    return data[0] if data else None
def sb_answers_by_student(student_id):
    if not supabase:
        return []
    res = supabase.table('answers').select('*').eq('student_id', student_id).order('id', desc=True).execute()
    return res.data or []

