@app.route('/teacher/analytics')
@teacher_required
def teacher_analytics():
    c = conn()
    top_questions = c.execute("""
        SELECT q.id, q.chapter, q.display_type, q.text,
               SUM(CASE WHEN a.smart_result LIKE '%خطأ%' OR a.smart_result='ناقص' THEN 1 ELSE 0 END) AS wrong_count,
               COUNT(a.id) AS total_answers
        FROM questions q
        LEFT JOIN answers a ON a.question_id = q.id
        GROUP BY q.id, q.chapter, q.display_type, q.text
        HAVING total_answers > 0
        ORDER BY wrong_count DESC, total_answers DESC, q.id DESC
        LIMIT 15
    """).fetchall()
    weak_chapters = c.execute("""
        SELECT q.chapter,
               SUM(CASE WHEN a.smart_result LIKE '%خطأ%' OR a.smart_result='ناقص' THEN 1 ELSE 0 END) AS wrong_count,
               COUNT(a.id) AS total_answers
        FROM questions q
        JOIN answers a ON a.question_id = q.id
        GROUP BY q.chapter
        HAVING total_answers > 0
        ORDER BY wrong_count DESC, total_answers DESC, q.chapter ASC
    """).fetchall()
    weak_types = c.execute("""
        SELECT q.display_type,
               SUM(CASE WHEN a.smart_result LIKE '%خطأ%' OR a.smart_result='ناقص' THEN 1 ELSE 0 END) AS wrong_count,
               COUNT(a.id) AS total_answers
        FROM questions q
        JOIN answers a ON a.question_id = q.id
        GROUP BY q.display_type
        HAVING total_answers > 0
        ORDER BY wrong_count DESC, total_answers DESC, q.display_type ASC
    """).fetchall()
    summary = {
        'answers': c.execute('SELECT COUNT(*) AS n FROM answers').fetchone()['n'],
        'wrong': c.execute("SELECT COUNT(*) AS n FROM answers WHERE smart_result LIKE '%خطأ%' OR smart_result='ناقص'").fetchone()['n'],
        'questions_seen': c.execute('SELECT COUNT(DISTINCT question_id) AS n FROM answers').fetchone()['n'],
    }
    c.close()
    body = '''
    <div class="card"><a class="btn" href="{{ url_for('teacher_dashboard') }}">رجوع</a></div>
    <div class="grid">
      <div class="card">إجابات الطلاب: {{ summary['answers'] }}</div>
      <div class="card">الإجابات الخاطئة أو الناقصة: {{ summary['wrong'] }}</div>
      <div class="card">الأسئلة التي جُرّبت: {{ summary['questions_seen'] }}</div>
    </div>
    <div class="card"><h3>الأسئلة الأكثر خطأ</h3>
      {% for q in top_questions %}
      <div class="q">
        <b>الفصل {{ q['chapter'] }}</b> — {{ q['display_type'] }}<br>
        {{ q['text'] }}<br>
        عدد الأخطاء: {{ q['wrong_count'] }} / {{ q['total_answers'] }}
      </div>
      {% else %}<div class="muted">لا توجد بيانات كافية بعد</div>{% endfor %}
    </div>
    <div class="grid">
      <div class="card"><h3>أكثر الفصول ضعفًا</h3>
        {% for ch in weak_chapters %}
        <div class="q">الفصل {{ ch['chapter'] }} — أخطاء: {{ ch['wrong_count'] }} / {{ ch['total_answers'] }}</div>
        {% else %}<div class="muted">لا توجد بيانات بعد</div>{% endfor %}
      </div>
      <div class="card"><h3>أكثر أنواع الأسئلة خطأ</h3>
        {% for t in weak_types %}
        <div class="q">{{ t['display_type'] }} — أخطاء: {{ t['wrong_count'] }} / {{ t['total_answers'] }}</div>
        {% else %}<div class="muted">لا توجد بيانات بعد</div>{% endfor %}
      </div>
    </div>
    '''
    return render_base('تحليل الأخطاء', render_template_string(body, summary=summary, top_questions=top_questions, weak_chapters=weak_chapters, weak_types=weak_types))





@app.route('/teacher/answers', methods=['GET', 'POST'])
@teacher_required
def teacher_answers():
    rows = []

